create extension if not exists btree_gist;
create type public.user_role as enum ('admin','user');create type public.reservation_status as enum ('confirmed','cancelled');
create table public.profiles (id uuid primary key references auth.users(id) on delete cascade,full_name text not null,email text not null,role public.user_role not null default 'user',created_at timestamptz not null default now());
create table public.rooms (id uuid primary key default gen_random_uuid(),name text not null,location text not null,type text not null,capacity integer not null check(capacity>0),equipment text[] not null default '{}',description text not null,is_active boolean not null default true,created_at timestamptz not null default now());
create table public.reservations (id uuid primary key default gen_random_uuid(),room_id uuid not null references public.rooms(id),user_id uuid not null references public.profiles(id),title text not null check(char_length(title) between 3 and 120),start_time timestamptz not null,end_time timestamptz not null,attendee_count integer not null check(attendee_count>0),notes text,status public.reservation_status not null default 'confirmed',cancelled_at timestamptz,created_at timestamptz not null default now(),check(end_time>start_time));
alter table public.reservations add constraint no_overlapping_reservations exclude using gist (room_id with =,tstzrange(start_time,end_time,'[)') with &&) where (status='confirmed');
create index reservations_room_time_idx on public.reservations(room_id,start_time);create index reservations_user_time_idx on public.reservations(user_id,start_time);create index rooms_search_idx on public.rooms using gin(to_tsvector('english',name||' '||location));
alter table public.profiles enable row level security;alter table public.rooms enable row level security;alter table public.reservations enable row level security;
create policy "profiles readable" on public.profiles for select to authenticated using (true);create policy "rooms readable" on public.rooms for select to authenticated using (is_active=true);create policy "own reservations readable" on public.reservations for select to authenticated using (user_id=auth.uid() or (select role from public.profiles where id=auth.uid())='admin');
create or replace function public.create_reservation_safely(p_room_id uuid,p_user_id uuid,p_title text,p_start_time timestamptz,p_end_time timestamptz,p_attendee_count integer,p_notes text) returns uuid language plpgsql security definer set search_path=public as $$ declare new_id uuid; begin insert into reservations(room_id,user_id,title,start_time,end_time,attendee_count,notes) values(p_room_id,p_user_id,p_title,p_start_time,p_end_time,p_attendee_count,p_notes) returning id into new_id; return new_id; end; $$;
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path=public as $$ begin insert into public.profiles(id,full_name,email) values(new.id,coalesce(new.raw_user_meta_data->>'full_name',split_part(new.email,'@',1)),new.email); return new; end; $$;create trigger on_auth_user_created after insert on auth.users for each row execute procedure public.handle_new_user();
